patch:
diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index 4f83b9cfa18d..d250721f763a 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -2998,16 +2998,20 @@ private:
   TreeEntry *getVectorizedOperand(TreeEntry *UserTE, unsigned OpIdx) {
     ArrayRef<Value *> VL = UserTE->getOperand(OpIdx);
     TreeEntry *TE = nullptr;
-    const auto *It = find_if(VL, [&](Value *V) {
+    // Search for a TreeEntry that matches VL and has EdgeInfo (UserTE, OpIdx).
+    for (Value *V : VL) {
       for (TreeEntry *E : getTreeEntries(V)) {
         if (is_contained(E->UserTreeIndices, EdgeInfo(UserTE, OpIdx))) {
-          TE = E;
-          return true;
+          // Found a candidate, check if it matches VL.
+          if (E->isSame(VL)) {
+            TE = E;
+            break;
+          }
         }
       }
-      return false;
-    });
-    if (It != VL.end()) {
+      if (TE) break;
+    }
+    if (TE) {
       assert(TE->isSame(VL) && "Expected same scalars.");
       return TE;
     }

